import { VectorStoreIndex, Document } from 'llamaindex';
import { verify } from '@vex/sdk';

const documents = new Document({
  text: deidentifiedClinicalData,
  metadata: { source: 'hipaa-compliant-emr' }
});

const index = await VectorStoreIndex.fromDocuments([documents]);
const queryEngine = index.asQueryEngine();

const safeQuery = verify({
  guards: [
    'index_age < 24h',
    'response.retrieved_chunks.length >= 3',
    'no_hallucinations(response, sources)',
    'chunk_boundary_integrity_preserved()'
  ]
})(async (query: string) => {
  return await queryEngine.query({ query });
});

const response = await safeQuery('Recommended antibiotic for this patient profile?');

from llama_index.core import StorageContext, load_index_from_storage
from vex import verify, AuditTrail

storage_context = StorageContext.from_defaults(...)
query_engine = load_index_from_storage(storage_context)

@verify(
    guards=[
        "audit_trail.complete()",
        "response.cites_sources_exclusively()",
        "no_phi_leakage_confirmed()"
    ],
    audit=True  # Enables FDA 21 CFR Part 11 compliance logging
)
def auditable_medical_rag(query: str) -> str:
    response = query_engine.query(query)
    AuditTrail.log({
        'query': query,
        'retrieved_nodes': response.source_nodes,
        'llm_output': str(response),
        'verification_passed': True
    })
    return str(response)

result = auditable_medical_rag('Current treatment guidelines for hypertension?')
